     * */
    appUpload(imageData) {
      var filePath = imageData;
      var devicePlatform = device.platform;
      filename = imageData.substring(
        imageData.lastIndexOf("/") + 1,
        imageData.length
      );
      if ("Android" == devicePlatform) {
        if (imageData.indexOf("file:///storage/emulated/0") == -1) {
          filePath = imageData.replace("file:///storage/sdcard0", "/sdcard");
        } else {
          filePath = imageData.replace("file:///storage/emulated/0", "/sdcard");
        }
      }

      if ("iOS" == devicePlatform) {
        filePath = imageData.replace("file:///", "/");
      }

      picPath = filePath;
      this.executeCompress(picPath);
      document.getElementById("sourceUrl").value = picPath;
      document.getElementById("downloadImage").src = picPath;
    },

    /**
     * 压缩图片		原生相机使用
     * */
    executeCompress(filePath) {
      alert("上传   filePath         " + filePath);
      mam.navigator.ContentCompression.getSmallPicture(
        function (obj) {
          alert("上传            " + obj.result);
          document.getElementById("sourceUrl").value = obj.result;
        },
        function (dlFileTransferError) {
          mam.navigator.notification.alert("压缩文件失败!");
        },
        filePath,
        800
      );
    },

    /**
     * 压缩文件上传成功函数
     * */
    successUploadPICCallback(obj) {
      var jsonObj = JSON.parse(obj);
      var fjId = jsonObj.file_id;
      /*	old
    var fjId = obj.toString();*/
      var fileId = "FILE_" + fjId;

      //将上传后的文件展示到页面中
      //  appendImgFun(fjId,picPath);

      //    if(sessionStorage.appendName!=""&&sessionStorage.appendName!=null){
      //    	//显示图片
      //        $('<div id="'+fjId+'" class="baseImg"><img id="'+fileId+'" src="' + picPath + '"  onclick="fileClick(event)" "></div>').appendTo(sessionStorage.appendName);
      //    }else{
      //    	//显示图片
      //        $('<div id="'+fjId+'" class="baseImg"><img id="'+fileId+'" src="' + picPath + '"  onclick="fileClick(event)" "></div>').appendTo('.cameraImgList');
      //    }
    },
    /**
