    errCallback(obj) {
      //mam.navigator.notification.alert("文件上传失败,请稍后重试!");
      layer.msg("文件上传失败,请稍后重试!");
    },
    /*---------------------- 文件上传到数据库   end  ----------------------*/

    /**
	下载完成 打开aac 
**/
    openMedia(fileName) {
      var fileUrl = this.getFileUrl(fileName);
      console.log("openMedia  fileUrl:  " + fileUrl);
      console.log("openMedia  fileUrl22:  " + "../../" + fileUrl);

      if (this.phoneType() == "ios") {
        //IOS 文件完整路径   igwsgcc300/serverfile/local_1597368143580045.jpg
        //IOS 存放与应用包同级目录  应用自定义文件夹。
        //document.getElementById("downloadImage").src = '../../'+fileUrl;

        document.getElementById("fileAACUrl").value = "../.../../" + fileUrl;
        document.getElementById("aacAudio").src = "../../" + fileUrl;
      } else if (this.phoneType() == "android") {
        // 安卓 与应用版本同级
        //document.getElementById("downloadImage").src = '../../../../'+fileUrl;

        document.getElementById("fileAACUrl").value = "../../../../" + fileUrl;
        document.getElementById("aacAudio").src = "../../../../" + fileUrl;
      }
      // 将基础信息清空，否则文件删除后有缓存
      //basefileInfo='';
    },
    /**

		录制 音频 aac格式
		开始录音
		参数说明：
			onSuccess	成功回调
			onError		失败回调
			filePath	文件路径  (无意义 待优化)

	**/
    startRecordAudio() {
      console.log("test()--->start()");
      if (!this.deviceReady) {
        //执行到这边表示cordova环境没有准备好
        return;
      }
      alert("startRecordAudio");
      var filePath = "/aacUrl";
      mam.navigator.audio.startRecordAudio(
        startonSuccess,
        startonError,
        filePath
      );

      function startonSuccess(data) {
        console.log("onSuccess() data:" + data);
      }

      //参数为string类型
      function startonError(data) {
        console.log("onError() data:" + data);
      }
      console.log("test()--->end()");
    },
    /**

	录制 音频 aac格式
	结束录音
	参数说明：
		onSuccess	成功回调
		onError		失败回调
	**/
    finishRecordAudio() {
      console.log("test()--->start()");
      if (!this.deviceReady) {
        //执行到这边表示cordova环境没有准备好
        return;
      }
      alert("finishRecordAudio");
      mam.navigator.audio.finishRecordAudio(finishonSuccess, finishonError);

      function finishonSuccess(data) {
        document.getElementById("fileAACUrl").value = data;

        document.getElementById("aacAudio").src = data;
        console.log("onSuccess() data:" + data);
      }
      function finishonError(data) {
        console.log("onError() data:" + data);
      }
      console.log("test()--->end()");
    },
    /**
	aac 文件上传
	参数说明：
		successCallback		成功回调
		errorCallback		失败回调
		appCode				应用编码
		appServerCode		应用服务编码		这里使用  upload6 
		path				本地文件路径	字符串
		params				上传参数  key:value
	**/
    uploadAAC() {
      var params = { param1: "upload6", param2: "这是param2  aac 文件上传" };
      var path = document.getElementById("fileAACUrl").value;
      mam.navigator.appfilemanage.appServerUpload(
        this.fileDownloadCallback,
        this.getFileListerrCallback,
        this.appCode,
        "upload6",
        path,
        params
      );
    },

    onLoadFileInfo() {
      var file = $("#fileUrl").get(0).files[0];
      var fileB = document.getElementById("fileUrl").value;
      $("#sourceUrl").val(fileB);
    },
  },
};
